import{_ as o,o as a,c as r,a0 as e}from"./chunks/framework.CSK6mTG2.js";const p=JSON.parse('{"title":"模型量化与剪枝：让大模型\\"瘦身\\"的两种思路","description":"","frontmatter":{"title":"模型量化与剪枝：让大模型\\"瘦身\\"的两种思路","author":"唐超","date":"2026-07-11T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/model-quantization-pruning.md","filePath":"menuAI/model-quantization-pruning.md"}'),d={name:"menuAI/model-quantization-pruning.md"};function n(u,t,i,l,q,h){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="模型量化与剪枝-让大模型-瘦身-的两种思路" tabindex="-1">模型量化与剪枝：让大模型&quot;瘦身&quot;的两种思路 <a class="header-anchor" href="#模型量化与剪枝-让大模型-瘦身-的两种思路" aria-label="Permalink to &quot;模型量化与剪枝：让大模型&quot;瘦身&quot;的两种思路&quot;">​</a></h1><p>你有没有这种感觉：买了一件大衣，回家发现太大了，想改小一点，但又不希望改完之后穿着走形？</p><p>大模型的&quot;瘦身&quot;问题跟这很像。一个 70B 参数的模型，光是参数就占 140GB 内存，普通的 GPU 根本跑不动。但你又不能随便删参数，否则模型回答质量问题。</p><p>所以就有了两种主流的&quot;改衣&quot;技术：<strong>量化（Quantization）</strong> 和 <strong>剪枝（Pruning）</strong>。今天我们就来聊聊它们各自是什么、有什么区别、什么时候用哪个。</p><h2 id="量化-把-精确数字-变成-简化代号" tabindex="-1">量化：把&quot;精确数字&quot;变成&quot;简化代号&quot; <a class="header-anchor" href="#量化-把-精确数字-变成-简化代号" aria-label="Permalink to &quot;量化：把&quot;精确数字&quot;变成&quot;简化代号&quot;&quot;">​</a></h2><h3 id="一个生活中的类比" tabindex="-1">一个生活中的类比 <a class="header-anchor" href="#一个生活中的类比" aria-label="Permalink to &quot;一个生活中的类比&quot;">​</a></h3><p>你去买水果，老板说&quot;苹果 5 块一斤&quot;。但如果他说&quot;苹果 4.7 块一斤&quot;，你大概率还是会当成&quot;大约 5 块&quot;来处理——因为精度到小数点后一位对你买水果这件事来说，没什么实际意义。</p><p><strong>量化就是这个思路</strong>：把模型里的高精度数字（FP32、FP16）用更少的位数来表示，从而减少内存占用和计算量。4.7 近似为 5，就是一种&quot;量化&quot;。</p><h3 id="具体怎么做的" tabindex="-1">具体怎么做的 <a class="header-anchor" href="#具体怎么做的" aria-label="Permalink to &quot;具体怎么做的&quot;">​</a></h3><p>模型参数在训练和推理时通常以 <strong>FP32（32位浮点）</strong> 存储，每个数字占 4 个字节。FP16 占 2 个字节，精度稍低。量化就是把这些 32 位或 16 位的数字&quot;压缩&quot;到 8 位（INT8）甚至 4 位（INT4）。</p><blockquote><p>打个比方：原来每个数字用&quot;厘米&quot;来量（精度高，占空间），现在改成用&quot;米&quot;来量（精度低一些，但占用空间只有 1/100）。</p></blockquote><p>常见的量化精度：</p><table tabindex="0"><thead><tr><th>格式</th><th>位宽</th><th>内存占用（70B 模型）</th><th>典型场景</th></tr></thead><tbody><tr><td>FP32</td><td>32bit</td><td>~280GB</td><td>训练</td></tr><tr><td>FP16/BF16</td><td>16bit</td><td>~140GB</td><td>推理基准</td></tr><tr><td>INT8</td><td>8bit</td><td>~70GB</td><td>量化推理</td></tr><tr><td>INT4</td><td>4bit</td><td>~35GB</td><td>极致压缩</td></tr></tbody></table><p>INT4 听起来很诱人——内存直接降为原来的 1/8！但精度损失也会更明显，回答可能变得&quot;不那么聪明&quot;。</p><h3 id="量化不是简单截断" tabindex="-1">量化不是简单截断 <a class="header-anchor" href="#量化不是简单截断" aria-label="Permalink to &quot;量化不是简单截断&quot;">​</a></h3><p>很多人以为量化就是&quot;把所有数字除以 2，然后取整&quot;，其实不是这样。量化过程中最关键的一步叫<strong>校准（Calibration）</strong>：需要用一小批真实数据跑一遍模型，找到合适的缩放因子（scale），让量化后的模型在精度损失最小的情况下运行。</p><p>打个比方：你有一把尺子，刻度是厘米，现在想换成刻度为米的尺子。但直接换会有误差，所以你要先用一批样本量一量，找一个最优的换算比例，让误差最小。这个&quot;找最优比例&quot;的过程就是校准。</p><p><strong>主流的量化方法</strong>：</p><ul><li><strong>GPTQ / AWQ</strong>：后训练量化（PTQ），在模型训练完之后做，效率高，精度损失可接受</li><li><strong>GGUF</strong>：LLM.cpp 生态的量化格式，把量化参数和权重一起打包，CPU 也能跑</li><li><strong>QAT（量化感知训练）</strong>：在训练时就模拟量化效果，让模型提前适应&quot;低精度&quot;状态</li></ul><h3 id="量化后的模型能干什么" tabindex="-1">量化后的模型能干什么 <a class="header-anchor" href="#量化后的模型能干什么" aria-label="Permalink to &quot;量化后的模型能干什么&quot;">​</a></h3><p>以 4-bit 量化的 Llama 3 70B 为例，原来需要 280GB 显存，现在只需要 35GB 左右，配上消费级双 RTX 3090 就能跑了。INT8 的版本大概需要 70GB，单卡 A100 80GB 刚好够。</p><p>这就是量化的价值：<strong>让大模型从&quot;只有大公司能跑&quot;变成&quot;科研团队也能玩得起&quot;</strong>。</p><h2 id="剪枝-把-不重要的地方-删掉" tabindex="-1">剪枝：把&quot;不重要的地方&quot;删掉 <a class="header-anchor" href="#剪枝-把-不重要的地方-删掉" aria-label="Permalink to &quot;剪枝：把&quot;不重要的地方&quot;删掉&quot;">​</a></h2><h3 id="另一个类比" tabindex="-1">另一个类比 <a class="header-anchor" href="#另一个类比" aria-label="Permalink to &quot;另一个类比&quot;">​</a></h3><p>你写一篇 5000 字的文章，回头看发现有两段话说的是同一个意思，删掉一段不影响阅读，反而更精简。大模型的剪枝就是这个思路：<strong>找到那些&quot;冗余&quot;或&quot;不重要&quot;的神经元/连接，把它们删掉</strong>。</p><h3 id="剪枝的两种类型" tabindex="-1">剪枝的两种类型 <a class="header-anchor" href="#剪枝的两种类型" aria-label="Permalink to &quot;剪枝的两种类型&quot;">​</a></h3><p><strong>1. 权重剪枝（Weight Pruning）</strong> 把那些数值接近零的连接直接删掉。直觉是：权重接近零意味着这个连接对最终结果影响很小，删了问题不大。就像你家的WiFi路由器，某个房间里信号特别弱（权重接近零），干脆就把那个节点删掉，不影响整体上网。</p><p><strong>2. 结构化剪枝（Structured Pruning）</strong> 权重剪枝虽然有效，但删除的是细粒度的连接，导致模型参数变得稀疏（到处都是零零碎碎的空洞），硬件加速困难。结构化剪枝干脆把整个神经元、整个注意力头、整个层一起删掉，形成一个&quot;天然紧凑&quot;的小模型。</p><blockquote><p>类比一下：权重剪枝像把一篇文章里每个句子里删掉几个不太重要的词，结果文章读起来断断续续；结构化剪枝像直接把某个段落删掉，剩下的段落完整连贯。</p></blockquote><h3 id="大模型剪枝的挑战" tabindex="-1">大模型剪枝的挑战 <a class="header-anchor" href="#大模型剪枝的挑战" aria-label="Permalink to &quot;大模型剪枝的挑战&quot;">​</a></h3><p>传统剪枝在 BERT 时代用得比较多，但大模型时代遇到了新问题：</p><ul><li><strong>大模型本身就是稀疏的</strong>：训练好的大模型中，很多权重本来就接近零，剪枝空间有限。</li><li><strong>难以判断&quot;不重要&quot;</strong>：大模型的能力往往是 emergent（涌现）的，你以为某个连接不重要，删掉后可能影响某个意想不到的能力。</li><li><strong>训练代价太高</strong>：剪枝后通常还需要微调来恢复性能，但大模型微调成本极高。</li></ul><p>所以目前主流的做法是<strong>稀疏化训练</strong>，而不是训练完再剪枝。即在训练时就施加正则化，鼓励模型天然形成稀疏结构，而不是训练完了再去删。</p><h2 id="量化和剪枝-选哪个" tabindex="-1">量化和剪枝：选哪个？ <a class="header-anchor" href="#量化和剪枝-选哪个" aria-label="Permalink to &quot;量化和剪枝：选哪个？&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>量化</th><th>剪枝</th></tr></thead><tbody><tr><td>原理</td><td>降低数字精度</td><td>删除不重要权重</td></tr><tr><td>内存影响</td><td>直接减少</td><td>部分减少</td></tr><tr><td>计算速度</td><td>显著提升</td><td>部分提升（需硬件支持稀疏计算）</td></tr><tr><td>精度损失</td><td>取决于位数</td><td>取决于剪枝比例</td></tr><tr><td>工程成熟度</td><td>高（GPTQ、GGUF 广泛使用）</td><td>中（结构化剪枝进展较快）</td></tr><tr><td>对硬件要求</td><td>降低（INT8/INT4 有硬件加速）</td><td>需要稀疏计算支持</td></tr></tbody></table><p><strong>实践中，量化用得更多</strong>，因为：</p><ol><li>工程实现成熟，工具链完善</li><li>精度损失可预期、可控</li><li>几乎所有硬件都对低精度计算有加速</li></ol><p>剪枝更适合当你需要<strong>彻底改变模型结构</strong>（比如从 70B 变成 7B 这种极端情况）时，配合微调来用。</p><h2 id="组合使用-1-1-2" tabindex="-1">组合使用：1+1 &gt; 2 <a class="header-anchor" href="#组合使用-1-1-2" aria-label="Permalink to &quot;组合使用：1+1 &gt; 2&quot;">​</a></h2><p>有趣的是，量化和剪枝可以叠加使用。先剪枝让模型变小，再量化把剩下的参数压缩到低位宽。很多开源社区的&quot;小模型&quot;就是这么来的——比如 Llama 3 70B 经过剪枝+INT4量化，可以压缩到只有 4GB，在手机端跑都勉强能用了。</p><blockquote><p>把这个过程想成装修：先拆掉不承重的墙（剪枝），再把剩下的家具缩小比例（量化）。最后原来的大三居变成了精装修的一居室，功能够用，但住起来完全没问题。</p></blockquote><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>理解量化和剪枝，有助于你理解为什么现在有那么多&quot;小模型&quot;可以选择。Qwen2 7B、Phi-3 Mini 这些小模型，很多都是在更大的模型上经过量化或剪枝得到的。</p><p>下次你在选模型时，如果看到 &quot;INT4量化版&quot; 或 &quot;4-bit Q5_K_M&quot; 这样的标注，就知道背后的技术原理了——模型被&quot;压缩&quot;过了，但核心能力还在。</p>',44)])])}const g=o(d,[["render",n]]);export{p as __pageData,g as default};
